1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	const COMPONENT_TYPES = ["rune"];
12	const COMPONENT_PREMIUM = 25;
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const isComponent = (item: Item): boolean =>
17	  COMPONENT_TYPES.includes(item.type);
18	
19	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
20	// BLOCK_PREMIUM; any other count is priced per component.
21	const componentGroupBasePremium = (count: number): number =>
22	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
23	
24	interface Item {
25	  type: string;
26	}
27	
28	interface QuoteStep {
29	  items: Item[];
30	}
31	
32	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
33	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
34	// that is only spuriously above a whole number.
35	const roundUpInMHPCOsFavor = (amount: number): number =>
36	  Math.ceil(Number(amount.toFixed(6)));
37	
38	const basePremiumForItem = (item: Item): number =>
39	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
40	
41	// Each main item is priced on its own.
42	const mainItemsBasePremium = (items: Item[]): number =>
43	  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
44	
45	const countByType = (items: Item[]): Map<string, number> => {
46	  const counts = new Map<string, number>();
47	  for (const item of items) {
48	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
49	  }
50	  return counts;
51	};
52	
53	// Components are grouped by type, and each group is block-priced.
54	const componentsBasePremium = (components: Item[]): number =>
55	  [...countByType(components).values()].reduce(
56	    (sum, count) => sum + componentGroupBasePremium(count),
57	    0,
58	  );
59	
60	export const quote = (
61	  customer: unknown,
62	  step: QuoteStep,
63	  quoteIndex: number,
64	): number => {
65	  const mainItems = step.items.filter((item) => !isComponent(item));
66	  const components = step.items.filter(isComponent);
67	
68	  const policyBasePremium =
69	    mainItemsBasePremium(mainItems) + componentsBasePremium(components);
70	  const withFirstInsurance = policyBasePremium * (1 + FIRST_INSURANCE_SURCHARGE);
71	  const total = withFirstInsurance + PROCESSING_FEE;
72	  return roundUpInMHPCOsFavor(total);
73	};
74	
75	export const claim = (...args: unknown[]): unknown => {
76	  return undefined; // Intentionally not implemented
77	};
